def collect_even(tree: dict, start: str, vals: dict) -> list:
    """Collect reachable even values, sorted."""
    out = []
    stack = [start]
    while stack:
        node = stack.pop()
        if vals[node] % 2 == 0:
            out.append(vals[node])
        stack.extend(tree.get(node, []))
    return sorted(out)
