def sieve_of_eratosthenes(n: Any) -> object {
    prime = [True] * (n + 1);
    prime[0] = prime[1]=False;
    p = 2;
    while ((p * p) <= n) {
        if (prime[p] == True) {
            for i in range((p * p), (n + 1), p) {
                prime[i] = False;
            }
        }
        p += 1;
    }
    primes = [
        i
        for i in range((n + 1))
        if prime[i]
    ];
    return primes;
}



