    words = sentence.split()
    reversed_sentence = []
    for word in words:
        if len(word) <= 5 or word[0].lower() in vowels:
            reversed_sentence.append(word)
    reversed_sentence.reverse()
    return ' '.join(reversed_sentence)
```

